create extension if not exists pgcrypto; create table public.profiles ( id uuid primary key references auth.users(id) on delete cascade, employee_name text not null, email text not null, role text not null default 'preparer' check (role in ('administrator', 'preparer')), active boolean not null default true, created_at timestamptz not null default now(), updated_at timestamptz not null default now() ); create table public.clients ( id uuid primary key default gen_random_uuid(), client_number text not null unique, first_name text, last_name text, business_name text, phone text, email text, preferred_contact_method text check ( preferred_contact_method is null or preferred_contact_method in ('Phone', 'Email', 'Text') ), client_type text not null default 'Individual' check ( client_type in ( 'Individual', 'Business', 'Nonprofit', 'Other' ) ), assigned_preparer_id uuid references public.profiles(id), active boolean not null default true, notes text, created_by uuid references auth.users(id), created_at timestamptz not null default now(), updated_at timestamptz not null default now() ); create table public.tax_returns ( id uuid primary key default gen_random_uuid(), client_id uuid not null references public.clients(id) on delete cascade, tax_year integer not null check (tax_year between 2000 and 2100), return_type text not null default 'Federal and State', date_received date, received_by uuid references public.profiles(id), delivery_method text check ( delivery_method is null or delivery_method in ( 'Walk-in', 'Portal', 'Email', 'Mail', 'Other' ) ), assigned_preparer_id uuid references public.profiles(id), current_status text not null default 'Documents Received' check ( current_status in ( 'Documents Received', 'Initial Review', 'Missing Information', 'Waiting for Client', 'Ready for Preparation', 'In Preparation', 'Ready for Quality Review', 'Corrections Required', 'Ready for Client Signature', 'Ready to File', 'E-Filed', 'Federal Accepted', 'State Accepted', 'Rejected', 'Amendment Required', 'Completed', 'On Hold', 'Cancelled' ) ), expected_completion_date date, completed_date date, federal_filed_date date, state_filed_date date, federal_acceptance_date date, state_acceptance_date date, follow_up_date date, preparation_fee numeric(10,2) not null default 0 check (preparation_fee >= 0), additional_fees numeric(10,2) not null default 0 check (additional_fees >= 0), discount numeric(10,2) not null default 0 check (discount >= 0), amount_paid numeric(10,2) not null default 0 check (amount_paid >= 0), payment_status text generated always as ( case when amount_paid = 0 then 'Unpaid' when amount_paid < greatest(preparation_fee + additional_fees - discount, 0) then 'Partial' else 'Paid' end ) stored, balance_due numeric(10,2) generated always as ( greatest( preparation_fee + additional_fees - discount - amount_paid, 0 ) ) stored, notes text, created_by uuid references auth.users(id), created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique (client_id, tax_year, return_type) ); create table public.status_history ( id uuid primary key default gen_random_uuid(), tax_return_id uuid not null references public.tax_returns(id) on delete cascade, previous_status text, new_status text not null, change_note text, changed_by uuid not null references auth.users(id), changed_at timestamptz not null default now() ); create table public.payments ( id uuid primary key default gen_random_uuid(), tax_return_id uuid not null references public.tax_returns(id) on delete cascade, payment_date date not null default current_date, amount numeric(10,2) not null check (amount > 0), payment_method text check ( payment_method is null or payment_method in ( 'Cash', 'Check', 'Credit Card', 'Debit Card', 'ACH', 'Other' ) ), reference_number text, received_by uuid references public.profiles(id), notes text, created_at timestamptz not null default now() ); create index clients_last_name_idx on public.clients(last_name); create index clients_business_name_idx on public.clients(business_name); create index tax_returns_status_idx on public.tax_returns(current_status); create index tax_returns_tax_year_idx on public.tax_returns(tax_year); create index tax_returns_client_id_idx on public.tax_returns(client_id); create index tax_returns_assigned_preparer_idx on public.tax_returns(assigned_preparer_id); create index status_history_return_idx on public.status_history(tax_return_id); create index payments_return_idx on public.payments(tax_return_id);